parameters.jsCode:
const candidates = $json.candidates || [];
const text = candidates?.[0]?.content?.parts?.[0]?.text || '';

let screening = {};
try {
  const jsonMatch = text.match(/```json\n?([\s\S]*?)\n?```/);
  if (jsonMatch) {
    screening = JSON.parse(jsonMatch[1]);
  } else {
    screening = JSON.parse(text);
  }
} catch (e) {
  screening = {
    match_score: 50,
    skills_match: [],
    skills_missing: [],
    experience_years: 0,
    experience_match: false,
    overall_verdict: 'partial_match',
    strengths: [],
    concerns: [],
    recommended_interview: false,
    interview_questions: []
  };
}

const prevData = $('Parse Resume Data').first().json;
return [{
  json: {
    candidate_name: prevData.candidate_name,
    candidate_email: prevData.candidate_email,
    job_title: prevData.job_title,
    match_score: screening.match_score || 0,
    skills_match: screening.skills_match || [],
    skills_missing: screening.skills_missing || [],
    experience_years: screening.experience_years || 0,
    experience_match: screening.experience_match || false,
    overall_verdict: screening.overall_verdict || 'partial_match',
    strengths: screening.strengths || [],
    concerns: screening.concerns || [],
    recommended_interview: screening.recommended_interview || false,
    interview_questions: screening.interview_questions || [],
    screened_at: new Date().toISOString()
  }
}];

